eseries_volume_read_latency{array=~"$Array",datacenter=~"$Datacenter",volume=~"$Volume"}
and on (datacenter, volume, array)
  topk(
    $TopResources,
    max by (datacenter, volume, array) (
      avg_over_time(
        eseries_volume_read_latency{array=~"$Array",datacenter=~"$Datacenter",volume=~"$Volume"}[3h] @ end()
      )
    )
  )

